```python
// Example 2: GitHub Copilot Inline Completion with Custom Prompts
// Demonstrates how to effectively use Copilot's completion features
// and the chat interface for complex refactoring tasks

// Inline completion trigger - type this comment and press Tab:
function processUserData(users) {
  // Process array of user objects and return formatted results
  // using modern JavaScript methods with error handling

  // Copilot will suggest:
  return users
    .filter(user => user && user.isActive)
    .map(user => ({
      name: user.name?.trim() || 'Unknown',
      email: user.email?.toLowerCase() || '',
      joinedDate: user.createdAt 
        ? new Date(user.createdAt).toLocaleDateString() 
        : 'N/A'
    }));
}

// Using Copilot Chat for complex debugging:
// Open Copilot Chat and ask:
// "Debug this function. Why is it returning undefined for some users?
//  Consider edge cases like missing properties and null values."

// Context-aware refactoring request via Copilot Chat:
// "Transform this callback-based code to use async/await with proper error handling.
//  Consider adding retry logic for network failures."

function fetchUserDataCallback(userId, callback) {
  // Old pattern - Copilot can transform this
  fetch(`/api/users/${userId}`, (error, response) => {
    if (error) return callback(error);
    parseUser(response, (err, user) => {
      if (err) return callback(err);
      callback(null, user);
    });
  });
}

// Refactored version (what Copilot might suggest):
async function fetchUserDataAsync(userId, maxRetries = 3) {
  let lastError;

  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const response = await fetch(`/api/users/${userId}`);
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }
      return await parseUserAsync(response);
    } catch (error) {
      lastError = error;
      if (attempt < maxRetries - 1) {
        await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, attempt)));
      }
    }
  }

  throw new Error(`Failed after ${maxRetries} attempts: ${lastError.message}`);
}

