# Configuration for Continue AI plugin (~/.continue/config.py)
# Supports multiple model backends for different tasks

from continuedev.src.continuedev.core.config import ContinueConfig
from continuedev.src.continuedev.libs.util.llm import CompletionOptions

def modify_config(config: ContinueConfig):
    """
    Configure Continue with multiple local model options.
    This allows switching between models based on task requirements.
    """

    # Fast model for quick completions and inline suggestions
    # Uses smaller model for speed: 7B parameters
    fast_model_config = {
        "title": "Mistral-7B (Fast)",
        "provider": "openai",
        "model": "mistral:7b",
        "api_base": "http://localhost:11434/v1",
        "api_key": "not-needed",
        "completion_options": CompletionOptions(
            temperature=0.3,      # Lower temp for consistent completions
            top_p=0.9,
            max_tokens=500,       # Shorter responses for speed
            repeat_penalty=1.1    # Reduce repetition
        )
    }

    # Powerful model for complex analysis and debugging
    # Uses larger model for quality: 13B parameters
    quality_model_config = {
        "title": "CodeLlama-13B (Quality)",
        "provider": "openai",
        "model": "codellama:13b",
        "api_base": "http://localhost:11434/v1",
        "api_key": "not-needed",
        "completion_options": CompletionOptions(
            temperature=0.8,      # Higher temp for creative analysis
            top_p=0.95,
            max_tokens=2000,      # Longer responses for detailed explanations
            repeat_penalty=1.0
        )
    }

    # Custom fine-tuned model for specific language
    # Requires custom model created with Ollama Modelfile
    custom_model_config = {
        "title": "Rust Expert (Custom)",
        "provider": "openai",
        "model": "rust-expert:latest",
        "api_base": "http://localhost:11434/v1",
        "api_key": "not-needed",
        "completion_options": CompletionOptions(
            temperature=0.6,
            top_p=0.9,
            max_tokens=1500
        )
    }

    # Update config with all models
    config.models.extend([fast_model_config, quality_model_config, custom_model_config])

    # Set default model
